@use 'tokens' as *;

:root {
  --color-background: #191919;
  --color-surface: #232325;
  --color-surface-hover: #2a2a2d;
  --color-text-primary: #e5e5ea;
  --color-accent: #007aff;
  --color-accent-hover: #0a84ff;
  --color-destructive: #ff453a;
  --color-destructive-hover: #ff5e55;
  --color-success: #30d158;
  --color-surface-footer: rgba(255, 255, 255, 0.05);
  --color-text-on-accent: #ffffff;
  --color-text-on-accent-secondary: rgba(255, 255, 255, 0.7);
  --color-kbd-background-on-accent: rgba(255, 255, 255, 0.15);
  --color-selection-background: rgba(0, 122, 255, 0.1);
  --color-code-background: rgba(255, 255, 255, 0.06);
  --color-tag-background: rgba(255, 255, 255, 0.1);
  --color-toggle-knob: #ffffff;
  --text-100: rgba(229, 229, 234, 0.1);
  --text-400: rgba(229, 229, 234, 0.4);
  --text-600: rgba(229, 229, 234, 0.6);
  --border-100: rgba(229, 229, 234, 0.1);
  --border-200: rgba(229, 229, 234, 0.2);
  --color-accent-15: rgba(0, 122, 255, 0.15);
  --color-accent-30: rgba(0, 122, 255, 0.3);
  --color-bg-40: rgba(25, 25, 25, 0.4);
  --color-surface-40: rgba(35, 35, 37, 0.4);
  --backdrop-overlay: rgba(0, 0, 0, 0.4);
  --backdrop-blur: 4px;
  --shadow-window:
    0 24px 80px rgba(0, 0, 0, 0.55), 0 2px 12px rgba(0, 0, 0, 0.35);
  --shadow-popover:
    0 12px 32px rgba(0, 0, 0, 0.45), 0 1px 6px rgba(0, 0, 0, 0.25);
  --color-scheme: dark;
  --date-picker-invert: 0.6;
}

[data-theme='light'] {
  --color-background: #ececec;
  --color-surface: #ffffff;
  --color-surface-hover: #f0f0f2;
  --color-text-primary: #1d1d1f;
  --color-accent: #007aff;
  --color-accent-hover: #0062cc;
  --color-destructive: #ff3b30;
  --color-destructive-hover: #e5342b;
  --color-success: #28cd41;
  --color-surface-footer: rgba(0, 0, 0, 0.03);
  --color-text-on-accent: #ffffff;
  --color-text-on-accent-secondary: rgba(255, 255, 255, 0.8);
  --color-kbd-background-on-accent: rgba(255, 255, 255, 0.2);
  --color-selection-background: rgba(0, 122, 255, 0.1);
  --color-code-background: rgba(0, 0, 0, 0.04);
  --color-tag-background: rgba(0, 0, 0, 0.06);
  --color-toggle-knob: #ffffff;
  --text-100: rgba(29, 29, 31, 0.1);
  --text-400: rgba(29, 29, 31, 0.4);
  --text-600: rgba(29, 29, 31, 0.6);
  --border-100: rgba(29, 29, 31, 0.1);
  --border-200: rgba(29, 29, 31, 0.2);
  --color-accent-15: rgba(0, 122, 255, 0.12);
  --color-accent-30: rgba(0, 122, 255, 0.2);
  --color-bg-40: rgba(236, 236, 236, 0.5);
  --color-surface-40: rgba(255, 255, 255, 0.5);
  --backdrop-overlay: rgba(0, 0, 0, 0.2);
  --backdrop-blur: 4px;
  --shadow-window:
    0 24px 80px rgba(0, 0, 0, 0.15), 0 2px 12px rgba(0, 0, 0, 0.1);
  --shadow-popover:
    0 12px 32px rgba(0, 0, 0, 0.12), 0 1px 6px rgba(0, 0, 0, 0.08);
  --color-scheme: light;
  --date-picker-invert: 0;
}

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: $font-md;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: $font-family;
  letter-spacing: -0.011em;
  background-color: var(--color-background);
  color: var(--color-text-primary);
}

::selection {
  background-color: var(--color-accent-30);
  color: inherit;
}

::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--border-100);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--border-200);
}

@keyframes palette-appear {
  from {
    opacity: 0;
    transform: scale(0.98) translateY(-8px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@keyframes action-panel-slide-up {
  from {
    opacity: 0;
    transform: translateY(8px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

