319→function ExtensionRow({
320→  ext,
321→  onToggle,
322→  showAuthor,
323→}: {
324→  ext: ExtensionEntry;
325→  onToggle: (id: string) => void;
326→  showAuthor: boolean;
327→}) {
328→  return (
329→    <div
330→      className="settings-extension"
331→      onClick={() => onToggle(ext.id)}
332→      role="button"
333→      tabIndex={0}
334→      onKeyDown={e => {
335→        if (e.key === 'Enter' || e.key === ' ') {
336→          e.preventDefault();
337→          onToggle(ext.id);
338→        }
339→      }}
340→    >
341→      <div className="settings-extension__icon">{ext.icon()}</div>
342→      <div className="settings-extension__info">
343→        <div className="settings-extension__name">{ext.name}</div>
344→        <div className="settings-extension__meta">
345→          {ext.description}
346→          {showAuthor && <> &middot; {ext.author}</>}
347→        </div>
348→      </div>
349→      <div className="settings-extension__toggle">
350→        <ToggleSwitch
351→          checked={ext.enabled}
352→          onChange={() => onToggle(ext.id)}
353→          label={`Toggle ${ext.name}`}
354→        />
355→      </div>
356→    </div>
357→  );
